184	    String schematicErrorCheck(FINotificationRequest fiNotificationRequest){
185	        HashMap<String, Object> stringObjectHashMap = new HashMap<>();
186	        String errorMessage = "";
187	        stringObjectHashMap.put("version", fiNotificationRequest.getVer());
188	        stringObjectHashMap.put("timeStamp", fiNotificationRequest.getTimestamp());
189	        stringObjectHashMap.put("txnId", fiNotificationRequest.getTxnid());
190	        stringObjectHashMap.put("notifier", fiNotificationRequest.getNotifier());
191	        stringObjectHashMap.put("fiNotificationRequest.FIStatus", fiNotificationRequest.getFIStatusNotification());
192	        stringObjectHashMap.put("fiNotificationRequest.FiStatusNotification.SessionId", fiNotificationRequest.getFIStatusNotification().getSessionId());
193	        stringObjectHashMap.put("fiNotificationRequest.FiStatusNotification.sessionStatus", fiNotificationRequest.getFIStatusNotification().getSessionStatus());
194	        stringObjectHashMap.put("fiNotificationRequest.FiStatusNotification.FIStatusResponse", fiNotificationRequest.getFIStatusNotification().getFIStatusResponse());
195	        stringObjectHashMap.put("notifier.Id", fiNotificationRequest.getNotifier().getId());
196	        stringObjectHashMap.put("notifier.type", fiNotificationRequest.getNotifier().getType());
197	        // iterate map and set the message for empty or null values
198	        for (String key : stringObjectHashMap.keySet())
199	        {
200	            if(NullEmptyUtils.isNull(stringObjectHashMap.get(key)) ||stringObjectHashMap.get(key).equals("")){
201	                errorMessage = errorMessage + key+",";
202	            }
203	        }
204	        return errorMessage;
205	    }
