207	    boolean checkSessionStatus(FINotificationRequest fiNotificationRequest){
208	        boolean isSessionStatusPresent = false;
209	        for (SessionStatus c : SessionStatus.values()) {
210	            if (c.name().contains(fiNotificationRequest.getFIStatusNotification().getSessionStatus())) {
211	                isSessionStatusPresent = true;
212	            }
213	        }
214	        return isSessionStatusPresent;
215	    }
