217	    void fiNotificationCallBack(ConsentEntity consentEntity, FIRequestEntity fiRequestEntity, String fiStatus) throws JWSSignatureException, DataException {
218	        FINotificationErrorResponseToFIU fiNotificationErrorResponseToFIU = new FINotificationErrorResponseToFIU();
219	        fiNotificationErrorResponseToFIU.setFiuConnectSessionId(consentEntity.getFiuConnectSessionId());
220	        fiNotificationErrorResponseToFIU.setFiStatus(fiStatus);
221	        fiNotificationErrorResponseToFIU.setVer(applicationConfigurationBean.getFiuConnectVersion());
222	        fiNotificationErrorResponseToFIU.setTimestamp(DateTimeUtil.getISOTimeStamp(System.currentTimeMillis()));
223	        fiNotificationErrorResponseToFIU.setTxnid(UUIDGenerator.generateUUID());
224	        fiNotificationErrorResponseToFIU.setErrorMsg(GeneralConstants.FI_STATUS_MSG+fiStatus);
225	        fiNotificationErrorResponseToFIU.setErrorCode(GeneralConstants.INVALID_REQUEST);
226	        callBackService.fiNotificationCallBack(fiNotificationErrorResponseToFIU,
227	                consentEntity.getConsentDetail().getDataConsumer().getId(), MDC.get(applicationConfigurationBean.getMdcLogId()));
