package com.finbit.fiuadapter.webservice.utils;

import java.util.Calendar;

import org.joda.time.DateTime;
import org.joda.time.DateTimeZone;
import org.joda.time.format.DateTimeFormat;
import org.joda.time.format.DateTimeFormatter;

/**
 * @author manjunathr created at 30-06-2020
 *         <p>
 *         This is the Util class used for the opertations related to Date and time
 */
public class DateTimeUtil {

    /**
     * This method is used to add the number of days and number of months to the given date
     *
     * @param currentMilliSecond
     * @param days
     * @param month
     *
     * @return result DateTime
     */
    public static String getAddedDate( Long currentMilliSecond, int days, int month )
    {
        DateTime date = new DateTime(currentMilliSecond, DateTimeZone.UTC);
        Calendar c = Calendar.getInstance();
        c.setTime(date.toDate());
        c.add(Calendar.DATE, days);
        c.add(Calendar.MONTH, month);
        return getISOTimeStamp(new DateTime(c.getTimeInMillis(), DateTimeZone.UTC).getMillis());
    }

    /**
     * This method returns DateTime in UTC format
     *
     * @return DateTime
     */
    public static DateTime getcurrentUTCTimeStamp()
    {
        return new DateTime(DateTimeZone.UTC);
    }

    public static String getISOTimeStamp( Long milliSecond )
    {
        DateTimeFormatter formatter = DateTimeFormat.forPattern("yyyy-MM-dd'T'hh:mm:ss.SSS'Z'");
        DateTime currentDate = new DateTime(milliSecond, DateTimeZone.UTC);
        return currentDate.toString(formatter);
    }
}

